messages.content:
Aquí tienes un ejemplo de cómo estructurar el JSON para emitir una factura electrónica de servicios (concepto 2) usando Afip SDK. Observa que no se incluye ningún campo para ítems; solo los totales y datos requeridos por AFIP:

```json
{
  "environment": "dev",
  "method": "FECAESolicitar",
  "wsid": "wsfe",
  "params": {
    "Auth": {
      "Token": "TU_TOKEN",
      "Sign": "TU_SIGN",
      "Cuit": "TU_CUIT"
    },
    "FeCAEReq": {
      "FeCabReq": {
        "CantReg": 1,
        "PtoVta": 1,
        "CbteTipo": 1
      },
      "FeDetReq": {
        "FECAEDetRequest": {
          "Concepto": 2,
          "DocTipo": 80,
          "DocNro": 33693450239,
          "CbteDesde": 10,
          "CbteHasta": 10,
          "CbteFch": "20240729",
          "FchServDesde": "20240729",
          "FchServHasta": "20240729",
          "FchVtoPago": "20240729",
          "ImpTotal": 59137.18,
          "ImpTotConc": 0,
          "ImpNeto": 48873.7,
          "ImpOpEx": 0,
          "ImpIVA": 10263.48,
          "ImpTrib": 0,
          "MonId": "PES",
          "MonCotiz": 1,
          "CondicionIVAReceptorId": 1,
          "Iva": {
            "AlicIva": [
              {
                "Id": 5,
                "BaseImp": 48873.7,
                "Importe": 10263.48
              }
            ]
          }
        }
      }
    }
  }
}
```
